import SwiftUIimport GoogleMapsstruct GoogleMapViewRepresentable: UIViewRepresentable {    var location: CLLocationCoordinate2D? // ✅ Now expecting CLLocationCoordinate2D?    func makeUIView(context: Context) -> GMSMapView {        let options = GMSMapViewOptions()        options.camera = GMSCameraPosition.camera(            withLatitude: 40.4296,            longitude: -86.9091,            zoom: 5        )        let mapView = GMSMapView(options: options)        mapView.isMyLocationEnabled = true        mapView.settings.myLocationButton = true        return mapView    }    func updateUIView(_ uiView: GMSMapView, context: Context) {        uiView.clear() // Clear existing markers        if let location = location {            let marker = GMSMarker(position: location)            marker.title = "Current Location"            marker.icon = GMSMarker.markerImage(with: .blue)            marker.map = uiView                        // Animate camera to new location            let camera = GMSCameraPosition.camera(                withLatitude: location.latitude,                longitude: location.longitude,                zoom: 15            )            uiView.animate(to: camera)        }    }}